def count_odd_elements(lst):
    if not lst:
        raise IndexError("List is empty")

    odd_count = 0
    for element in lst:
        if not isinstance(element, int):
            raise ValueError("List contains non-integer elements")
        if element % 2 != 0:
            odd_count += 1

    return odd_count

