    // Define a simple progression that increments by 1
    let increment = |x| x + 1;

    // Create a new progression starting from 0
    let mut prog = NumProgression::new(0, increment);

    // Print the first 5 values in the progression
    for _ in 0..5 {
        println!("{}", prog.next());
    }
}
```
