        if (resultatJoueur2 === 6) {
            joueur2 = true;
            break;
        }

        tour++;
    }

    if (joueur1) {
        console.log("Joueur 1 gagne !");
    } else if (joueur2) {
        console.log("Joueur 2 gagne !");
    }
}

jouer();
```

