Voici une implémentation d'une classe C++ pour un vecteur 3D avec les fonctionnalités demandées :

```cpp
#include <iostream>
#include <cmath>
#include <stdexcept>

class Vector3D {
private:
    double x, y, z;

public:
    // Constructeur
    Vector3D(double x = 0, double y = 0, double z = 0) : x(x), y(y), z(z) {}

    // Addition de vecteurs
    Vector3D operator+(const Vector3D& v) const {
        return Vector3D(x + v.x, y + v.y, z + v.z);
    }

    // Soustraction de vecteurs
    Vector3D operator-(const Vector3D& v) const {
        return Vector3D(x - v.x, y - v.y, z - v.z);
    }

    // Produit scalaire
    double dot(const Vector3D& v) const {
        return x * v.x + y * v.y + z * v.z;
    }

    // Produit vectoriel
    Vector3D cross(const Vector3D& v) const {
        return Vector3D(
            y * v.z - z * v.y,
            z * v.x - x * v.z,
            x * v.y - y * v.x
        );
    }

    // Magnitude (norme)
    double magnitude() const {
        return std::sqrt(x * x + y * y + z * z);
    }

    // Normalisation
    Vector3D normalize() const {
        double mag = magnitude();
        if (mag == 0) {
            throw std::runtime_error("Erreur : normalisation d'un vecteur nul.");
        }
        return Vector3D(x / mag, y / mag, z / mag);
    }

    // Affichage
    friend std::ostream& operator<<(std::ostream& os, const Vector3D& v) {
        os << "(" << v.x << ", " << v.y << ", " << v.z << ")";
        return os;
    }
};

int main() {
    try {
        Vector3D v1(1, 2, 3);
        Vector3D v2(4, 5, 6);

        std::cout << "v1 + v2 = " << v1 + v2 << std::endl;
        std::cout << "v1 - v2 = " << v1 - v2 << std::endl;
        std::cout << "Dot product: " << v1.dot(v2) << std::endl;
        std::cout << "Cross product: " << v1.cross(v2) << std::endl;
        std::cout << "Magnitude of v1: " << v1.magnitude() << std::endl;
        std::cout << "Normalized v1: " << v1.normalize() << std::endl;
    } catch (const std::runtime_error& e) {
        std::cerr << e.what() << std::endl;
    }

    return 0;
}
```

### Explications :

1. **Constructeur** : Permet de créer un vecteur 3D avec des coordonnées données ou par défaut (0, 0, 0).

2. **Opérations de base** :
   - **Addition** et **soustraction** sont définies à l'aide des opérateurs `+` et `-`.

3. **Produit scalaire** : Renvoie un `double` représentant le produit scalaire entre deux vecteurs.

4. **Produit vectoriel** : Renvoie un nouveau vecteur représentant le produit vectoriel de deux vecteurs.

5. **Magnitude** : Calcule la norme du vecteur.

6. **Normalisation** : Renvoie un vecteur unitaire (même direction, norme 1). Vérifie que la norme n'est pas nulle pour éviter la division par zéro.

7. **Gestion des erreurs** : Utilise `std::runtime_error` pour gérer les erreurs, comme la tentative de normalisation d'un vecteur nul.
